        let age = now - created;
        if age < threshold {
            continue; // Too young to prune
        }

        let name = container
            .names
            .as_ref()
            .and_then(|n| n.first())
            .map(|n| n.trim_start_matches('/').to_string())
            .unwrap_or_default();

        if name.is_empty() {
            continue;
        }

        match self
            .docker
            .remove_container(
                &name,
                Some(RemoveContainerOptions {
                    force: true,
                    ..Default::default()
                }),
            )
            .await
        {
            Ok(()) => {
                info!(spoke = %name, age_secs = age, "Pruned exited spoke");
                pruned.push(name);
            }
            Err(e) => {
                warn!(spoke = %name, error = %e, "Failed to prune spoke");
            }
        }
    }

    Ok(pruned)
}
